UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee job seeker visa approval?","a":"No. Embassy assesses recognition, funds, and credibility. Never promise approval or employment."},{"q":"Job seeker vs Opportunity Card?","a":"Opportunity Card uses points system; traditional job seeker requires recognised degree. Assess which fits."},{"q":"Can work while searching?","a":"Generally cannot work on job seeker visa—limited exceptions. Verify current rules."},{"q":"How long to find job?","a":"Visa typically 6 months—employment must match qualification level."},{"q":"Blocked account amount?","a":"Verify current requirement—similar to student amount (~€11,904 for 2026)."},{"q":"Recognition process time?","a":"ZAB statement can take weeks—start early."},{"q":"After job offer?","a":"Apply for work residence permit at Ausländerbehörde."},{"q":"Does visa guarantee job?","a":"No. Visa allows search only—employment depends on market and qualifications."},{"q":"What is Description for this service?","a":"National visa allowing qualified professionals with recognised German-equivalent degree to search for employment in Germany, typically up to 6 months."},{"q":"What is Eligible applicants for this service?","a":"Recognised higher education qualification · Sufficient funds (blocked account) · Health insurance · CV and job search plan · May need vocational recognition for some fields"},{"q":"What is Recognition prerequisite for this service?","a":"Degree must be recognised as equivalent to German qualification via Anabin or statement of comparability."},{"q":"Important note on Recognition prerequisite?","a":"Degree must be recognised as equivalent to German qualification via Anabin or statement of comparability."},{"q":"What is Key authority for this service?","a":"German Embassy in India · ZAB for recognition · Ausländerbehörde after arrival"},{"q":"What is After approval for this service?","a":"Enter Germany; attend interviews; convert to work permit when employment secured."},{"q":"Is Recognised qualification (Anabin/ZAB) required?","a":"Verify before apply"},{"q":"Is Blocked account or financial proof required?","a":"Assess whether Blocked account or financial proof is satisfied for this case."},{"q":"Is Health insurance for stay required?","a":"Assess whether Health insurance for stay is satisfied for this case."},{"q":"Is Detailed CV and cover letter required?","a":"Detailed CV and cover letter is typically required."},{"q":"Is Job search plan required?","a":"Job search plan is typically required."},{"q":"Is Valid passport required?","a":"Valid passport is typically required."},{"q":"Is Accommodation plan in Germany required?","a":"Accommodation plan in Germany is typically required."},{"q":"What is the Processing time?","a":"8–12w — Embassy processing"},{"q":"What is the Government fee?","a":"€75 — National visa approx"},{"q":"What is the Our approval rate?","a":"79% — ~68% benchmark"},{"q":"What is the Required docs?","a":"13 — + recognition & funds"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & blocked account"},{"q":"What if the client has Degree not recognised?","a":"Apply for recognition; consider Opportunity Card if eligible"},{"q":"Why is Degree not recognised a problem?","a":"Qualification not equivalent on Anabin/ZAB."},{"q":"What if the client has Insufficient blocked account?","a":"Open blocked account for full required period"},{"q":"Why is Insufficient blocked account a problem?","a":"Funds below required amount."}]'::jsonb
),
